{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a topological embedding task. To maximize empty cells, we need to find the smallest possible representation of the color adjacency graph that preserves connectivity and adjacency. This requires graph analysis and a layout algorithm.",
  "helpers": [
    {
      "label": "graph_analyzer",
      "instructions": "Analyze the input 50x50 grid to extract the adjacency graph of colors 1 to M. For each color, identify its neighbors (colors it is adjacent to in the input). Also, verify the connectivity of each color group in the input to ensure the graph representation is accurate. Output a list of edges representing the color adjacency graph."
    },
    {
      "label": "layout_optimizer",
      "instructionss": "Given the adjacency graph of colors, find a way to embed these colors into a 50x50 grid such that: 1. Each color occupies at least one cell. 2. If two colors are adjacent in the graph, they must be adjacent in the grid. 3. If they are not adjacent in the graph, they must not be adjacent in the grid. 4. Each color's cells must be connected. The goal is to use the minimum number of cells possible to maximize the number of 0 cells. Suggest a coordinate mapping for each color."
    },
    {
      "label": "code_generator",
      "instructions": "Write a Python script main.py that reads the 50x50 grid from stdin, processes the input, and outputs a 50x50 grid. The script should implement a robust version of the layout found by the layout_optimizer. It must handle the input format correctly and ensure the output is exactly 50 lines of 50 integers, adhering to all connectivity and adjacency constraints."
    }
  ],
  "synthesis_brief": "Combine the adjacency graph from the graph_analyzer with the spatial layout from the layout_optimizer to create a mapping of colors to grid coordinates. Use this mapping to guide the code_generator in producing a main.py that outputs a valid, high-scoring grid."
}

